* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: "Basis Grotesque Pro";
}

img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.container {
  position: fixed;
  width: 100vw;
  height: 100vh;
  background: #000;
  overflow: hidden;
}

nav {
  position: fixed;
  width: 100%;
  padding: 2em;
  display: flex;
  align-items: center;
  z-index: 2;
}

nav p,
footer p {
  color: #fff;
  font-size: 12px;
}

nav > div {
  flex: 1;
}

.menu-btn p {
  width: max-content;
  background: rgba(255, 255, 255, 0.1);
  border-radius: 40px;
  backdrop-filter: blur(20px);
  padding: 6px 12px;
}

.logo {
  display: flex;
  justify-content: center;
}

.local-time {
  display: flex;
  justify-content: flex-end;
}

.logo a {
  text-decoration: none;
  color: #fff;
  font-size: 20px;
  font-weight: 500;
}

footer {
  position: fixed;
  bottom: 0;
  width: 100%;
  padding: 2em;
  display: flex;
  justify-content: space-between;
  align-items: center;
  z-index: 2;
}

.items {
  position: fixed;
  width: 30%;
  height: 100vh;
  padding: 0 2em;
  display: flex;
  flex-direction: column;
  justify-content: center;
  z-index: 2;
}

.item {
  width: max-content;
  padding: 0.25em 0;
  cursor: pointer;
}

.item p {
  color: #fff;
  padding: 6px 12px;
  font-weight: lighter;
  background: rgba(255, 255, 255, 0.1);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 40px;
  backdrop-filter: blur(20px);
  transition: 0.3s;
}

.item:hover p {
  background: none;
  border: 1px solid rgba(255, 255, 255, 0.25);
}

.preview {
  position: fixed;
  width: 100vw;
  height: 100vh;
  z-index: 0;
}

.preview-bg {
  position: absolute;
  width: 100%;
  height: 100%;
